"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[129663],{936133:e=>{e.exports=JSON.parse('{"tag":{"label":"herd","permalink":"/dst-api-webdocs/docs/tags/herd","allTagsPath":"/dst-api-webdocs/docs/tags","count":14,"items":[{"id":"game-scripts/prefabs/babybeefalo","title":"Babybeefalo","description":"A growth-stage-based animal prefab that matures through defined life phases, interacts with beefalo herds, and supports combat, foraging, and periodic waste production.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/babybeefalo"},{"id":"game-scripts/prefabs/beefaloherd","title":"Beefaloherd","description":"Manages a herd of beefalo, handling seasonal mating behavior, member aggregation, and automatic spawning of baby beefalo during mating season.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beefaloherd"},{"id":"game-scripts/brains/deerbrain","title":"Deerbrain","description":"Manages the behavior tree for deer entities, coordinating solo and herd-based AI including fleeing, wandering, grazing, and alert responses.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/deerbrain"},{"id":"game-scripts/prefabs/domesticplantherd","title":"Domesticplantherd","description":"Creates a non-networked herd entity for Lunar Plants that manages group spawning, member aggregation, and automatic removal when the herd becomes empty.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/domesticplantherd"},{"id":"game-scripts/prefabs/grassgekkoherd","title":"Grassgekkoherd","description":"Creates a non-networked herd entity that manages a group of grassgekko entities using the herd system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/grassgekkoherd"},{"id":"game-scripts/components/herd","title":"Herd","description":"Manages a group of herd members (e.g., beefalo) around a central entity, handling membership, gathering, merging, position updates, and persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/components/herd"},{"id":"game-scripts/components/herdmember","title":"Herdmember","description":"Tracks herd membership for an entity and manages herd creation or rejoining when enabled.","permalink":"/dst-api-webdocs/docs/game-scripts/components/herdmember"},{"id":"game-scripts/prefabs/lightninggoat","title":"Lightninggoat","description":"Implements the lightning goat entity with charging behavior, passive electric retaliation, and herd-based AI.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightninggoat"},{"id":"game-scripts/prefabs/lightninggoatherd","title":"Lightninggoatherd","description":"A spawner entity that maintains a herd of lightning goats and periodically generates new members during mating season.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightninggoatherd"},{"id":"game-scripts/prefabs/mossling","title":"Mossling","description":"Implements the Mossling prefab, a seasonal creature that spawns during winter and summer in DST, with herd-based AI, combat behaviors, and seasonal lifespan logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mossling"},{"id":"game-scripts/prefabs/penguinherd","title":"Penguinherd","description":"A non-networked entity component that manages a herd of penguins, coordinating their spawning via mood cycles and the periodic spawner system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/penguinherd"},{"id":"game-scripts/prefabs/rockyherd","title":"Rockyherd","description":"Manages the herd system for spawning and maintaining groups of Rocky entities in the world, including seasonal spawning behavior and member population limits.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rockyherd"},{"id":"game-scripts/brains/squidbrain","title":"Squidbrain","description":"Controls AI behavior for squid entities, managing movement, combat, fishing interactions, and herd coordination.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/squidbrain"},{"id":"game-scripts/prefabs/squidherd","title":"Squidherd","description":"Manages a migratory herd of squid entities, handling member aggregation, navigation between predefined waypoints, and cleanup when all members are inactive or off-ocean.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/squidherd"}],"unlisted":false}}')}}]);